  const esc=s=>s.replace(/[\\()]/g,'\\$&');
  const stream = `BT /F1 18 Tf 40 90 Td (${esc(text)}) Tj ET`;
  const objs = [
    `1 0 obj${eol}<< /Type /Catalog /Pages 2 0 R >>${eol}endobj${eol}`,
    `2 0 obj${eol}<< /Type /Pages /Kids [3 0 R] /Count 1 >>${eol}endobj${eol}`,
