    `5 0 obj${eol}<< /Length ${Buffer.byteLength(stream)} >>${eol}stream${eol}${stream}${eol}endstream${eol}endobj${eol}`,
  ];
  let pdf=`%PDF-1.4${eol}`;
  const offsets=[0];
  for (const o of objs) { offsets.push(Buffer.byteLength(pdf)); pdf += o; }
