const {
  WATCH_DIRECTORY,
  ACCEPTED_MIMES,
  SUPPORTED_FILETYPE_CONVERTERS,
} = require("../constants");
const fs = require("fs");
const path = require("path");
const { pipeline } = require("stream/promises");
const { validURL } = require("../url");
const { default: slugify } = require("slugify");

function extensionFromContentType(contentType) {
  const mime = contentType?.toLowerCase().split(";")[0].trim();
  const extensions = ACCEPTED_MIMES[mime] || [];
  return extensions.find((extension) =>
    SUPPORTED_FILETYPE_CONVERTERS.hasOwnProperty(extension)
  );
}

function withContentTypeExtension(filename, contentType) {
  const fileExtension = path.extname(filename).toLowerCase();
  if (SUPPORTED_FILETYPE_CONVERTERS.hasOwnProperty(fileExtension))
    return filename;

  const inferredExtension = extensionFromContentType(contentType);
  return inferredExtension ? `${filename}${inferredExtension}` : filename;
}

