const hotdir = path.resolve('./collector/hotdir');
function clean(fileLocation) {
  if (fileLocation) fs.rmSync(fileLocation, { force: true });
}
function assert(condition, message) {
  if (!condition) throw new Error(message);
}

const server = http.createServer((req, res) => {
  const headers = {};
  if (!req.url.includes('no-get-type')) headers['Content-Type'] = 'application/pdf; charset=binary';
  res.writeHead(200, headers);
  res.end(Buffer.from([0x25, 0x50, 0x44, 0x46, 0x2d, 0x31, 0x2e, 0x34]));
});

server.listen(0, '127.0.0.1', async () => {
  const { port } = server.address();
  const cases = [
    {
      name: 'unsupported numeric suffix gets inferred PDF extension',
      url: `http://127.0.0.1:${port}/pdf/2307.10265`,
      args: [],
      check: (base) => base.endsWith('2307.10265.pdf'),
    },
    {
      name: 'existing supported extension is preserved',
      url: `http://127.0.0.1:${port}/files/report.pdf`,
      args: [],
      check: (base) => base.endsWith('report.pdf') && !base.endsWith('report.pdf.pdf'),
    },
    {
      name: 'passed content type is used when GET header is absent',
      url: `http://127.0.0.1:${port}/no-get-type/2307.10265`,
      args: [10_000, 'application/pdf'],
      check: (base) => base.endsWith('2307.10265.pdf'),
    },
  ];

  try {
    for (const testCase of cases) {
      const result = await downloadURIToFile(testCase.url, ...testCase.args);
      assert(result.success, `${testCase.name} download failed: ${result.reason}`);
      const base = path.basename(result.fileLocation);
      console.log(`${testCase.name}: ${base}`);
      assert(testCase.check(base), `${testCase.name} produced unexpected filename: ${base}`);
      assert(fs.existsSync(path.join(hotdir, base)), `${base} missing from hotdir`);
      clean(result.fileLocation);
    }
  } finally {
    server.close();
  }
}).on('error', (error) => {
  console.error(error);
  process.exit(1);
});
